import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import { useToast } from "../../context/ToastContext";
import Spinner from "../shared/Spinner";

export default function RegisterPage() {
  const { register } = useAuth();
  const { showToast } = useToast();
  const navigate = useNavigate();

  const [form, setForm]       = useState({ name: "", email: "", password: "", confirmPass: "" });
  const [error, setError]     = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    setError("");
    if (!form.name || !form.email || !form.password) { setError("All fields are required"); return; }
    if (form.password !== form.confirmPass) { setError("Passwords do not match"); return; }
    if (form.password.length < 6) { setError("Password must be at least 6 characters"); return; }

    setLoading(true);
    try {
      const u = await register({ name: form.name, email: form.email, password: form.password });
      showToast(`Account created! Welcome, ${u.name.split(" ")[0]}!`, "🎉");
      navigate("/dashboard");
    } catch (err) {
      setError(err.response?.data?.message || "Registration failed");
    } finally {
      setLoading(false);
    }
  };

  const fields = [
    { label: "Full Name",        key: "name",        type: "text",     ph: "Rahul Sharma" },
    { label: "Email",            key: "email",       type: "email",    ph: "you@example.com" },
    { label: "Password",         key: "password",    type: "password", ph: "Min 6 characters" },
    { label: "Confirm Password", key: "confirmPass", type: "password", ph: "Repeat password" },
  ];

  return (
    <div
      className="min-h-screen flex items-center justify-center p-6"
      style={{ background: "linear-gradient(135deg, #0D0F1A 0%, #1a2744 60%, #0D0F1A 100%)" }}
    >
      <div className="bg-white rounded-2xl p-9 w-full max-w-md shadow-[0_32px_80px_rgba(0,0,0,.35)] animate-fadeUp">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-10 h-10 bg-ink rounded-xl flex items-center justify-center text-lg">🏛️</div>
          <div className="font-display font-extrabold text-xl text-ink">Create Account</div>
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-800 rounded-lg px-4 py-3 text-sm mb-4">
            ⚠️ {error}
          </div>
        )}

        {fields.map(({ label, key, type, ph }) => (
          <div key={key} className="mb-4">
            <label className="block text-[13px] font-semibold text-ink mb-1.5">{label}</label>
            <input
              className="input-field"
              type={type}
              placeholder={ph}
              value={form[key]}
              onChange={(e) => setForm({ ...form, [key]: e.target.value })}
              onKeyDown={(e) => e.key === "Enter" && handleSubmit()}
            />
          </div>
        ))}

        <button className="btn-primary w-full py-3 text-base mt-2" onClick={handleSubmit} disabled={loading}>
          {loading ? <><Spinner /> Creating account…</> : "Create Account →"}
        </button>

        <p className="text-center text-sm text-slate-500 mt-5">
          Already have an account?{" "}
          <span
            className="text-ink font-semibold cursor-pointer underline"
            onClick={() => navigate("/login")}
          >
            Sign in
          </span>
        </p>
      </div>
    </div>
  );
}
